import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../core/utils/app_utils.dart';import '../data/app_repository.dart';class ReportsScreen extends ConsumerWidget{const ReportsScreen({super.key});bool same(DateTime a,DateTime b)=>a.year==b.year&&a.month==b.month&&a.day==b.day;@override Widget build(BuildContext context,WidgetRef ref){final now=DateTime.now(),sales=(ref.watch(salesProvider).valueOrNull??[]).where((x)=>same(x.createdAt,now)),expenses=(ref.watch(expensesProvider).valueOrNull??[]).where((x)=>same(x.createdAt,now)),debts=ref.watch(debtsProvider).valueOrNull??[],products=ref.watch(productsProvider).valueOrNull??[];final revenue=sales.fold<double>(0,(s,x)=>s+x.totalAmount),cost=sales.fold<double>(0,(s,x)=>s+x.totalCost),expense=expenses.fold<double>(0,(s,x)=>s+x.amount),outstanding=debts.fold<double>(0,(s,x)=>s+x.balance),low=products.where((x)=>x.quantity<=x.lowStockThreshold).length;Widget metric(String l,String v)=>Card(child:Padding(padding:const EdgeInsets.all(20),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(l),const SizedBox(height:6),Text(v,style:const TextStyle(fontSize:20,fontWeight:FontWeight.w900))])));return Scaffold(appBar:AppBar(title:const Text('Reports')),body:ListView(padding:const EdgeInsets.all(16),children:[Text('Today',style:Theme.of(context).textTheme.headlineSmall?.copyWith(fontWeight:FontWeight.w900)),const SizedBox(height:12),metric('Sales revenue',formatGhs(revenue)),const SizedBox(height:10),metric('Gross profit',formatGhs(revenue-cost)),const SizedBox(height:10),metric('Net profit',formatGhs(revenue-cost-expense)),const SizedBox(height:10),metric('Expenses',formatGhs(expense)),const SizedBox(height:10),metric('Outstanding customer debt',formatGhs(outstanding)),const SizedBox(height:10),metric('Low-stock products','$low')]));}}
